package testdata

// The certs below are a self-signed test CA plus a server cert (SAN 127.0.0.1)
// and client cert issued by it, all SHA256-signed. Go's crypto/x509 rejects
// SHA1-signed certificates during verification, so these must stay SHA256 (or
// stronger) to keep working.
var (
	caCrt     = ``
	serverKey = ``
	serverCrt = ``
	clientCrt = ``
	clientKey = ``
	// MockCerts holds a self-signed CA plus a matching server (SAN 127.0.0.1)
	// and client cert pair, used by tests to exercise mutual TLS.
	MockCerts = struct {
		Ca        string
		ServerKey string
		ServerCrt string
		ClientCrt string
		ClientKey string
	}{
		Ca:        caCrt,
		ServerCrt: serverCrt,
		ServerKey: serverKey,
		ClientKey: clientKey,
		ClientCrt: clientCrt,
	}
)
